PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?governor ?education WHERE {
  ?office wdt:P31 wd:Q986239 ; wdt:P131 ?state .
  ?state wdt:P17 wd:Q30 .
  ?governor wdt:P39 ?office .
  FILTER NOT EXISTS {
    ?office wdt:P576 ?end
  }
  .
  ?governor wdt:P1352 ?education .
}

